import React, { useState } from 'react';
import { Trash2, Edit2, Plus } from 'lucide-react';

const CategoryManager = ({ categories, onCreate, onUpdate, onDelete }) => {
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({ name: '', icon: '', color: '' });
  const [isCreating, setIsCreating] = useState(false);

  const handleEditClick = (category) => {
    setEditingId(category.id);
    setEditForm({ name: category.name, icon: category.icon, color: category.color });
  };

  const handleSaveEdit = async () => {
    await onUpdate(editingId, editForm);
    setEditingId(null);
  };

  const handleCreateNew = async () => {
    if (!editForm.name) return;
    await onCreate(editForm);
    setIsCreating(false);
    setEditForm({ name: '', icon: '', color: '' });
  };

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-syne font-bold">Manage Categories</h2>
        <button 
          onClick={() => {
            setIsCreating(true);
            setEditForm({ name: '', icon: '📁', color: '#95A5A6' });
          }}
          className="btn-primary flex items-center gap-2 text-sm"
        >
          <Plus className="w-4 h-4" /> Add New
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {isCreating && (
          <div className="bg-card border-2 border-accent border-dashed rounded-xl p-4 shadow-lg shadow-accent/5">
            <div className="space-y-3 mb-4">
              <input 
                className="input-field w-full text-sm" 
                placeholder="Category Name"
                value={editForm.name}
                onChange={e => setEditForm({...editForm, name: e.target.value})}
              />
              <div className="flex gap-2">
                <input 
                  className="input-field w-16 text-center text-xl" 
                  placeholder="🛒"
                  value={editForm.icon}
                  onChange={e => setEditForm({...editForm, icon: e.target.value})}
                  maxLength={2}
                />
                <input 
                  type="color"
                  className="w-10 h-10 rounded cursor-pointer shrink-0 bg-transparent"
                  value={editForm.color}
                  onChange={e => setEditForm({...editForm, color: e.target.value})}
                />
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => setIsCreating(false)} className="flex-1 btn-secondary text-sm">Cancel</button>
              <button onClick={handleCreateNew} className="flex-1 btn-primary text-sm">Save</button>
            </div>
          </div>
        )}

        {categories.map((cat) => (
          <div key={cat.id} className="bg-card border border-border rounded-xl p-4 flex flex-col hover:border-border-light transition-colors">
            {editingId === cat.id ? (
              <div className="space-y-3 mb-4">
                <input 
                  className="input-field w-full text-sm" 
                  value={editForm.name}
                  onChange={e => setEditForm({...editForm, name: e.target.value})}
                />
                <div className="flex gap-2">
                  <input 
                    className="input-field w-16 text-center text-xl" 
                    value={editForm.icon}
                    onChange={e => setEditForm({...editForm, icon: e.target.value})}
                    maxLength={2}
                  />
                  <input 
                    type="color"
                    className="w-10 h-10 border-0 rounded cursor-pointer shrink-0 bg-transparent"
                    value={editForm.color}
                    onChange={e => setEditForm({...editForm, color: e.target.value})}
                  />
                </div>
                <div className="flex gap-2 mt-4">
                  <button onClick={() => setEditingId(null)} className="flex-1 btn-secondary text-xs">Cancel</button>
                  <button onClick={handleSaveEdit} className="flex-1 btn-primary text-xs">Update</button>
                </div>
              </div>
            ) : (
              <>
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-10 h-10 rounded-xl flex items-center justify-center text-xl shadow-inner" style={{ backgroundColor: `${cat.color}20` }}>
                    <span style={{ color: cat.color }}>{cat.icon}</span>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className="font-medium text-text-primary truncate">{cat.name}</h3>
                    <p className="text-xs text-text-muted">{cat.transactionCount || 0} transactions</p>
                  </div>

                  <div className="flex opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => handleEditClick(cat)} className="p-1.5 text-text-muted hover:text-accent transition-colors">
                      <Edit2 className="w-4 h-4" />
                    </button>
                    {!['Uncategorized'].includes(cat.name) && (
                      <button onClick={() => onDelete(cat.id)} className="p-1.5 text-text-muted hover:text-danger transition-colors">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    )}
                  </div>
                </div>
              </>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default CategoryManager;
